  ('aboriginal-a5729396-moex-00019', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依照原住民族健康法的規定，醫療機構、護理機構、老人福利機構、長期照顧服務機構及其他健康照護服 務機構應鼓勵所屬人員修習何種課程，以提升原住民族健康照護之服務品質？', '["原民文化概論", "原住民族文化安全", "原住民族健康概論", "原住民族基本法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00020', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '為協助地方政府執行前瞻基礎建設計畫有關原住民族部落營造相關工作，原住民族委員會訂定計畫補助地 方政府進用專案人力，以提升執行效能。根據最近一期補助計畫內容，下列有關該項專案人力補助計畫之 敘述，何者正確？', '["進用之專案人力限為具原住民身分者", "補助對象限轄有文化健康站之直轄市及縣市政府", "專案人力所需費用採全額補助", "專案人力工作項目包括協助提升前瞻基礎建設部落營造工作項下各工程進度執行率"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00021', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '原住民族委員會刻正執行都市地區原住民族發展方案（112年～116年），請問下列對該方案之敘述，何者 錯誤？', '["依該方案內容說明，目前原住民人口設籍於非原住民族地區者已近5成", "該方案嘗試透過都市地區教會開設族語學習班，以提高族語認證通過率", "該方案具體措施包括將原住民族文化健康站設置工作擴展至都會區", "在該方案項下，由客家委員會推動原住民族與客家青年體育交流活動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00022', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依照原住民族教育法的規定，中央政府應寬列預算，專款辦理原住民族教育；其比率，合計不得少於中央 教育主管機關預算總額之比率為何？並依其需求逐年成長。', '["1.9%", "2.6%", "1.3%", "3.7%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
